#!/usr/bin/env bash
# topic-4.sh — 平台 决策助手 for 网文写作.
# Auto-generated by cli_writer.py. Source: synthesis.md Section 2 (Playbook).
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="网文写作"
TOPIC="平台"

usage() {
  cat <<EOF
topic-4.sh — ${TOPIC} 决策助手 for ${INDUSTRY}

基于 2 条 playbook 规则的交互式决策评估。
你描述情景, 工具帮你判断哪条规则适用, 并给推荐。

USAGE:
  ./topic-4.sh             # interactive
  ./topic-4.sh --dry-run   # walk through but no file
  ./topic-4.sh --json      # JSON to stdout
  ./topic-4.sh --explain   # show backing playbook rules + mental models
  ./topic-4.sh --help      # this message
EOF
}

explain() {
  cat <<'EOT'
这个决策助手把 平台 主题下的 playbook 规则组合成交互树。

基于 2 条规则:
  • 如果 开新书发书 → 则 发书前按自身手速攒约 3-10 万字存稿（业内经验法则）、定一个能稳住的日更量，别零存稿硬日更。案例：飞卢式首日爆更 1
  • 如果 想用 AI 提效 → 则 只用于非创作核心（起名/查资料/捋多线逻辑/大纲初稿）、正文人工重写，并留意平台 AI 政策红线。案例：起点 2025 

相关心智模型:
  • 黄金三章定生死：为留人而非为铺垫写开局: 网文开局不是慢热铺垫，是前三章/万字内必须抛出金手指 + 制造冲突 + 埋钩子 + 建立代入，否则签约率与追读直接塌——「最惨/最爽不过三章」。
  • 爽点是可理性设计的工程对象，不是灵感: 愤怒的香蕉「一开始是欲望，到后来是情绪，最后变成需求」——爽点能被作者主动观察、拆解、设计，心理描写可把爽感挖到极致，而非等灵感降临。

来源: synthesis.md Section 2.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a RULE_CONDITIONS=(
  "开新书发书"
  "想用 AI 提效"
)
declare -a RULE_ACTIONS=(
  "发书前按自身手速攒约 3-10 万字存稿（业内经验法则）、定一个能稳住的日更量，别零存稿硬日更。案例：飞卢式首日爆更 10 章抢流量 vs 晋江式质量稳更，按平台 + 产能选打法。(evidence: [T03-S013, T03-S004])"
  "只用于非创作核心（起名/查资料/捋多线逻辑/大纲初稿）、正文人工重写，并留意平台 AI 政策红线。案例：起点 2025 全面禁 AI 文、番茄整治批量产文；烽火戏诸侯「支持新人技巧性用 AI，坚决反对头部使用」。(evidence: [T01-S009, T03-S017])"
)
declare -a APPLIED_RULES=()

ms_section "${INDUSTRY} · ${TOPIC} 决策评估"
ms_info "本工具基于 ${#RULE_CONDITIONS[@]} 条 playbook 规则评估你的情景。"
echo

ms_prompt "请描述当前情景 (空行结束):"
echo
SITUATION="$(ms_read_multiline)"

for i in "${!RULE_CONDITIONS[@]}"; do
  ms_section "Rule $((i+1))/${#RULE_CONDITIONS[@]}"
  echo "适用情景: ${RULE_CONDITIONS[$i]}"
  echo "推荐做法: ${RULE_ACTIONS[$i]}"
  if ms_confirm "这条规则 fit 你当前情景吗?"; then
    APPLIED_RULES+=("$((i+1))")
    ms_ok "适用 rule $((i+1))"
  fi
done

ms_buffer_append "# ${INDUSTRY} — ${TOPIC} 决策报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 情景"
ms_buffer_append ""
ms_buffer_append "$SITUATION"
ms_buffer_append ""
ms_buffer_append "## 适用规则"
ms_buffer_append ""
if [[ ${#APPLIED_RULES[@]} -eq 0 ]]; then
  ms_buffer_append "(无适用 playbook 规则 — 此情景在已知 OS 之外, 建议回到 SKILL.md 心智模型层重新分析)"
else
  for ridx in "${APPLIED_RULES[@]}"; do
    i=$((ridx-1))
    ms_buffer_append "- **情景**: ${RULE_CONDITIONS[$i]} → **做法**: ${RULE_ACTIONS[$i]}"
  done
fi
ms_buffer_append ""

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "topic" "${TOPIC}" \
    "situation" "${SITUATION}" \
    "applied_rules_count" "${#APPLIED_RULES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "topic-4-decision"
fi
